scwin.f_Retrieve = async function () {
  let ret;
  dma_searchMonthCostPlan.set("distYn", "1"); // 배부포함여부를 항상 포함으로 고정함.(2006.04.13)
  if (ed_sacctDeptCd.getValue().trim() != "") {
    // 조회조건 필수사항 체크
    ret = await $c.gus.cfValidate($p, [ed_FromDate, ed_sacctDeptCd, lc_version, ed_coCd]);
    if (!ret) {
      return;
    }
  } else if (ed_sbizDomCd.getValue().trim() != "") {
    // 조회조건 필수사항 체크
    ret = await $c.gus.cfValidate($p, [ed_FromDate, ed_sbizDomCd, lc_version, ed_coCd]);
    if (!ret) {
      return;
    }
  } else {
    $c.gus.cfAlertMsg($p, "부서 혹은 사업영역중 하나는 필수 입력 입니다.");
    return;
  }

  // 귀속부서로 조회 할 경우
  if (ed_sacctDeptCd.getValue().trim() != "") {
    dma_searchMonthCostPlan.set("acctDeptCd", lc_acctDeptCd.getValue());
    dma_searchMonthCostPlan.set("bizDomCd", "");
    // 사업영역으로 조회 할 경우
  } else if (ed_sbizDomCd.getValue().trim() != "") {
    dma_searchMonthCostPlan.set("bizDomCd", lc_acctDeptCd.getValue());
    dma_searchMonthCostPlan.set("acctDeptCd", "");
  } else {
    $c.gus.cfAlertMsg($p, "부서 혹은 사업영역중 하나는 필수 입력 입니다.");
    return;
  }
  $c.sbm.execute($p, sbm_searchMonthCostPlan);
  //tr_searchMonthCostPlan.Post();
};
