scwin.f_changeUnit = function () {
  if (lc_unit.getValue() == "01") {
    scwin.f_changeUnitAmt(1);
  } else if (lc_unit.getValue() == "02") {
    scwin.f_changeUnitAmt(1000);
  } else if (lc_unit.getValue() == "03") {
    scwin.f_changeUnitAmt(1000000);
  } else if (lc_unit.getValue() == "04") {
    scwin.f_changeUnitAmt(100000000);
  }
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnitAmt = function (unitAmt) {
  if (!ds_MonthCostPlan_org || ds_MonthCostPlan_org.getRowCount() === 0) {
    return;
  }
  let calculatedData = ds_MonthCostPlan_org.getAllJSON();
  const cols = ["amt", "jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec", "halfYy", "halfYy2"];
  for (let i = 0; i < calculatedData.length; i++) {
    let rowData = calculatedData[i];
    for (const colId of cols) {
      if (rowData.hasOwnProperty(colId)) {
        //console.log("colId =>" + colId);
        let originalValue = parseFloat(rowData[colId] || 0);
        rowData[colId] = Math.round(originalValue / unitAmt);
        ds_MonthCostPlan.setCellData(i, colId, rowData[colId]);
      }
    }
  }
  //ds_MonthCostPlan.setJSON(calculatedData); origin 에서 복사 했기에 비율이 없다.
};
